const rows = $input.all();

const vendorTotals = {};
let grandTotal = 0;
let overdueCount = 0;
const today = new Date();

for (const row of rows) {
  const vendor = row.json['Vendor'] || 'Unknown';
  const total = parseFloat(row.json['Total']) || 0;
  const dueDate = new Date(row.json['Due Date']);

  if (!vendorTotals[vendor]) {
    vendorTotals[vendor] = { total: 0, count: 0, overdue: 0 };
  }

  vendorTotals[vendor].total += total;
  vendorTotals[vendor].count += 1;
  grandTotal += total;

  if (dueDate < today) {
    vendorTotals[vendor].overdue += 1;
    overdueCount += 1;
  }
}

let tableRows = '';
for (const [vendor, data] of Object.entries(vendorTotals)) {
  const overdueFlag = data.overdue > 0 ? '⚠️ ' + data.overdue + ' overdue' : '✅ Clear';
  tableRows += `
    <tr>
      <td style="padding:8px;border:1px solid #ddd">${vendor}</td>
      <td style="padding:8px;border:1px solid #ddd">${data.count}</td>
      <td style="padding:8px;border:1px solid #ddd">$${data.total.toFixed(2)}</td>
      <td style="padding:8px;border:1px solid #ddd">${overdueFlag}</td>
    </tr>`;
}

const html = `
<h2>Weekly Invoice Summary</h2>
<p>Period: last 7 days | Total invoices: ${rows.length} | Grand total: $${grandTotal.toFixed(2)}</p>
<table style="border-collapse:collapse;width:100%">
  <tr style="background:#f2f2f2">
    <th style="padding:8px;border:1px solid #ddd">Vendor</th>
    <th style="padding:8px;border:1px solid #ddd">Invoices</th>
    <th style="padding:8px;border:1px solid #ddd">Total</th>
    <th style="padding:8px;border:1px solid #ddd">Status</th>
  </tr>
  ${tableRows}
</table>
<p style="color:gray;font-size:12px">Generated automatically by Invoice Automation Pipeline</p>
`;

return [{ json: { html, grandTotal, totalInvoices: rows.length, overdueCount } }];
